import { HealthService } from '../../services/health.service.js';
import { navigate } from '../../router.js';
import { buildSectionPage } from '../../utils/section-page.utils.js';
import { createScreenStatusNodes, createScreenStatusMixin } from '../_shared/screen-status.js';
import { createComponentLogger } from '../../utils/component-logger.js';
import { safeExec } from '../../utils/safe-exec.js';
import { documentStyleSheet } from '../../utils/css.js';
import './workout-template-editor/workout-template-editor.component.js';
import type { WorkoutTemplateEditor } from './workout-template-editor/workout-template-editor.component.js';
import type { Exercise, NewWorkoutTemplateWithBlocks, WorkoutTemplate } from '@motivation/shared';
import type { ScreenComponent } from '../../types/screen-component.js';
import stylesText from './health-workout-templates-screen.css?inline';

documentStyleSheet(stylesText);

/**
 * Workout template management at `/health/workout-templates` (story 144). Lists
 * non-archived templates, with create/edit (reusing workout-template-editor),
 * archive, and "Start session" (expands the template into a new session via the
 * from-template route, then opens the strength screen). One editor shows at a
 * time in a holder above the list. Refetches on mount.
 */
export class HealthWorkoutTemplatesScreen extends HTMLElement implements ScreenComponent {
    private initialized = false;
    private contentRoot: HTMLElement | null = null;
    private formHolder: HTMLElement | null = null;
    private listRoot: HTMLElement | null = null;
    private templates: WorkoutTemplate[] = [];
    private library: Exercise[] = [];

    private readonly log = createComponentLogger('health-workout-templates-screen');
    private statusNodes = createScreenStatusNodes();
    private statusMixin = createScreenStatusMixin(this.statusNodes.loadingNode, this.statusNodes.errorNode, this.statusNodes.retryNode);

    setLoading(): void { this.statusMixin.setLoading(); }
    setError(err: unknown): void { this.statusMixin.setError(err); }
    clearStatus(): void { this.statusMixin.clearStatus(); }

    connectedCallback(): void {
        if (this.initialized) return;
        this.initialized = true;

        const page = buildSectionPage(this, 'Workout templates', 'health', '/health');
        this.contentRoot = page.content;

        const addBtn = document.createElement('button');
        addBtn.type = 'button';
        addBtn.className = 'wtl__btn wtl__btn--primary';
        addBtn.textContent = '+ New template';
        addBtn.dataset.testid = 'wtl-add';
        addBtn.addEventListener('click', () => this.openEditor(null));

        this.formHolder = document.createElement('div');
        this.formHolder.className = 'wtl__form-holder';
        this.listRoot = document.createElement('ul');
        this.listRoot.className = 'wtl__list';

        this.statusNodes.loadingNode.textContent = 'Loading templates…';
        this.statusNodes.retryNode.addEventListener('click', () => { void this.load(); });

        this.contentRoot.append(
            this.statusNodes.loadingNode, this.statusNodes.errorNode, this.statusNodes.retryNode,
            addBtn, this.formHolder, this.listRoot,
        );

        void this.load();
    }

    private async load(): Promise<void> {
        return safeExec(this, this.log, async () => {
            const [templates, library] = await Promise.all([
                HealthService.listWorkoutTemplates(),
                HealthService.listExercises(),
            ]);
            this.templates = templates;
            this.library = library;
            this.renderList();
        });
    }

    private renderList(): void {
        if (!this.listRoot) return;
        if (this.templates.length === 0) {
            const empty = document.createElement('li');
            empty.className = 'wtl__empty';
            empty.textContent = 'No templates yet — create one to reuse a workout.';
            this.listRoot.replaceChildren(empty);
            return;
        }
        this.listRoot.replaceChildren(...this.templates.map((t) => this.renderRow(t)));
    }

    private renderRow(t: WorkoutTemplate): HTMLElement {
        const row = document.createElement('li');
        row.className = 'wtl__row';

        const info = document.createElement('div');
        info.className = 'wtl__info';
        const name = document.createElement('span');
        name.className = 'wtl__name';
        name.textContent = t.name;
        const meta = document.createElement('span');
        meta.className = 'wtl__meta';
        meta.textContent = `used ${t.use_count}×${t.last_used_at ? ` · last ${t.last_used_at.slice(0, 10)}` : ''}`;
        info.append(name, meta);

        const actions = document.createElement('div');
        actions.className = 'wtl__row-actions';
        actions.append(
            this.actionBtn('Start', 'primary', () => { void this.startSession(t); }),
            this.actionBtn('Edit', 'default', () => { void this.openEditor(t.id); }),
            this.actionBtn('Archive', 'default', () => { void this.archive(t); }),
        );
        row.append(info, actions);
        return row;
    }

    private actionBtn(label: string, variant: 'primary' | 'default', onClick: () => void): HTMLButtonElement {
        const btn = document.createElement('button');
        btn.type = 'button';
        btn.className = variant === 'primary' ? 'wtl__btn wtl__btn--primary' : 'wtl__btn';
        btn.textContent = label;
        btn.addEventListener('click', onClick);
        return btn;
    }

    private async openEditor(id: string | null): Promise<void> {
        return safeExec(this, this.log, async () => {
            const editor = document.createElement('workout-template-editor') as WorkoutTemplateEditor;
            editor.library = this.library;
            editor.template = id ? await HealthService.getWorkoutTemplate(id) : null;
            editor.onCancel = () => this.formHolder?.replaceChildren();
            editor.onSave = (payload) => { void this.handleSave(id, payload, editor); };
            this.formHolder!.replaceChildren(editor);
        });
    }

    private async handleSave(id: string | null, payload: NewWorkoutTemplateWithBlocks, editor: WorkoutTemplateEditor): Promise<void> {
        try {
            if (id) await HealthService.updateWorkoutTemplate(id, payload);
            else await HealthService.createWorkoutTemplate(payload);
            this.formHolder?.replaceChildren();
            await this.load();
        } catch (err) {
            this.log.warn('Failed to save template', { err });
            editor.showError('Could not save the template.');
        }
    }

    private async archive(t: WorkoutTemplate): Promise<void> {
        if (!confirm(`Archive "${t.name}"? Past sessions that used it are unaffected.`)) return;
        return safeExec(this, this.log, async () => {
            await HealthService.archiveWorkoutTemplate(t.id);
            await this.load();
        });
    }

    private async startSession(t: WorkoutTemplate): Promise<void> {
        const date = prompt('Log this template for which date?', todayIso());
        if (!date) return;
        if (!/^\d{4}-\d{2}-\d{2}$/.test(date.trim())) {
            this.setError(new Error('Enter a date as YYYY-MM-DD.'));
            return;
        }
        return safeExec(this, this.log, async () => {
            const result = await HealthService.logTemplate(t.id, { date: date.trim() });
            navigate(`/health/workouts/${encodeURIComponent(result.activity_id)}`);
        });
    }
}

function todayIso(): string {
    // Local calendar date (en-CA renders as YYYY-MM-DD).
    return new Date().toLocaleDateString('en-CA');
}

customElements.define('health-workout-templates-screen', HealthWorkoutTemplatesScreen);
