import stylesText from './workout-template-editor.css?inline';
import { cssStyleSheet } from '../../../utils/css.js';
import type { Exercise, NewWorkoutTemplateWithBlocks, WorkoutTemplateWithBlocks } from '@motivation/shared';

const styles = cssStyleSheet(stylesText);

interface RowState {
    exercise_id: string;
    target_set_count: number;
    target_reps?: number;
    target_weight_kg?: number;
    target_rpe?: number;
    target_rest_s?: number;
}

/**
 * Create/edit form for a workout template's strength-set prescription (story
 * 144) — name, notes, and ordered exercise rows with optional targets (only
 * target_set_count is required, per spike D6). Callback-driven; the parent owns
 * persistence. Editing carries the template's existing interval `blocks`
 * through unchanged so the wholesale update never destroys them (a dedicated
 * template-blocks editor is a later addition).
 */
export class WorkoutTemplateEditor extends HTMLElement {
    private _library: Exercise[] = [];
    private _template: WorkoutTemplateWithBlocks | null = null;
    private rows: RowState[] = [];
    private _onSave: ((payload: NewWorkoutTemplateWithBlocks) => void) | null = null;
    private _onCancel: (() => void) | null = null;

    private root: HTMLElement;
    private nameInput!: HTMLInputElement;
    private notesInput!: HTMLInputElement;
    private rowsRoot!: HTMLElement;
    private errorEl!: HTMLElement;

    constructor() {
        super();
        const shadow = this.attachShadow({ mode: 'open' });
        shadow.adoptedStyleSheets = [styles];
        this.root = document.createElement('div');
        shadow.appendChild(this.root);
    }

    set library(value: Exercise[]) { this._library = [...value].sort((a, b) => a.display_name.localeCompare(b.display_name)); }
    set template(value: WorkoutTemplateWithBlocks | null) {
        this._template = value;
        this.rows = (value?.strength_sets ?? []).map((s) => ({
            exercise_id: s.exercise_id,
            target_set_count: s.target_set_count,
            target_reps: s.target_reps,
            target_weight_kg: s.target_weight_kg,
            target_rpe: s.target_rpe,
            target_rest_s: s.target_rest_s,
        }));
        this.render();
    }
    set onSave(handler: (payload: NewWorkoutTemplateWithBlocks) => void) { this._onSave = handler; }
    set onCancel(handler: () => void) { this._onCancel = handler; }

    connectedCallback(): void { if (!this.root.hasChildNodes()) this.render(); }

    private render(): void {
        this.root.replaceChildren();
        const form = document.createElement('form');
        form.className = 'wte';
        form.addEventListener('submit', (e) => { e.preventDefault(); this.handleSave(); });

        this.nameInput = labelledInput('Name', 'text', this._template?.name ?? '', 'e.g. Push Day A');
        this.notesInput = labelledInput('Notes', 'text', this._template?.notes ?? '', 'optional');

        this.rowsRoot = document.createElement('div');
        this.rowsRoot.className = 'wte__rows';

        const addRow = document.createElement('button');
        addRow.type = 'button';
        addRow.className = 'wte__btn';
        addRow.textContent = '+ Add exercise';
        addRow.addEventListener('click', () => {
            this.rows.push({ exercise_id: '', target_set_count: 3 });
            this.renderRows();
        });

        this.errorEl = document.createElement('p');
        this.errorEl.className = 'wte__error';
        this.errorEl.hidden = true;

        const actions = document.createElement('div');
        actions.className = 'wte__actions';
        const cancel = document.createElement('button');
        cancel.type = 'button';
        cancel.className = 'wte__btn';
        cancel.textContent = 'Cancel';
        cancel.addEventListener('click', () => this._onCancel?.());
        const save = document.createElement('button');
        save.type = 'submit';
        save.className = 'wte__btn wte__btn--primary';
        save.textContent = this._template ? 'Save template' : 'Create template';
        actions.append(cancel, save);

        form.append(wrapField('Name', this.nameInput), wrapField('Notes', this.notesInput), this.rowsRoot, addRow, this.errorEl, actions);
        this.root.appendChild(form);
        this.renderRows();
    }

    private renderRows(): void {
        this.rowsRoot.replaceChildren(...this.rows.map((row, index) => this.renderRow(row, index)));
    }

    private renderRow(row: RowState, index: number): HTMLElement {
        const el = document.createElement('div');
        el.className = 'wte__row';

        const exercise = document.createElement('select');
        exercise.className = 'wte__input wte__exercise';
        const placeholder = document.createElement('option');
        placeholder.value = '';
        placeholder.textContent = 'Select exercise…';
        exercise.appendChild(placeholder);
        for (const ex of this._library) {
            const o = document.createElement('option');
            o.value = ex.id;
            o.textContent = ex.display_name;
            exercise.appendChild(o);
        }
        exercise.value = row.exercise_id;
        exercise.addEventListener('change', () => { row.exercise_id = exercise.value; });

        const sets = numInput('Sets', row.target_set_count, (v) => { row.target_set_count = v ?? 0; });
        const reps = numInput('Reps', row.target_reps, (v) => { row.target_reps = v; });
        const weight = numInput('Kg', row.target_weight_kg, (v) => { row.target_weight_kg = v; });
        const rpe = numInput('RPE', row.target_rpe, (v) => { row.target_rpe = v; });
        const rest = numInput('Rest s', row.target_rest_s, (v) => { row.target_rest_s = v; });

        const targets = document.createElement('div');
        targets.className = 'wte__targets';
        targets.append(sets, reps, weight, rpe, rest);

        const rowActions = document.createElement('div');
        rowActions.className = 'wte__row-actions';
        rowActions.append(
            iconBtn('↑', () => this.move(index, -1)),
            iconBtn('↓', () => this.move(index, 1)),
            iconBtn('✕', () => { this.rows.splice(index, 1); this.renderRows(); }),
        );

        el.append(exercise, targets, rowActions);
        return el;
    }

    private move(index: number, delta: number): void {
        const j = index + delta;
        if (j < 0 || j >= this.rows.length) return;
        [this.rows[index], this.rows[j]] = [this.rows[j], this.rows[index]];
        this.renderRows();
    }

    private handleSave(): void {
        const name = this.nameInput.value.trim();
        if (!name) { this.showError('Enter a template name.'); return; }
        const validRows = this.rows.filter((r) => r.exercise_id && r.target_set_count > 0);
        if (validRows.length === 0) { this.showError('Add at least one exercise with a set count.'); return; }

        const payload: NewWorkoutTemplateWithBlocks = {
            name,
            notes: this.notesInput.value.trim() || undefined,
            strength_sets: validRows.map((r) => ({
                exercise_id: r.exercise_id,
                target_set_count: r.target_set_count,
                target_reps: r.target_reps,
                target_weight_kg: r.target_weight_kg,
                target_rpe: r.target_rpe,
                target_rest_s: r.target_rest_s,
            })),
            // Carry existing interval blocks through unchanged — the server update
            // replaces children wholesale, so omitting them would delete them.
            blocks: (this._template?.blocks ?? []).map((b) => ({
                parent_label: b.parent_label,
                kind: b.kind,
                modality: b.modality,
                target_duration_s: b.target_duration_s,
                target_distance_m: b.target_distance_m,
                target_intensity: b.target_intensity,
                notes: b.notes,
            })),
        };
        this._onSave?.(payload);
    }

    showError(message: string): void {
        this.errorEl.textContent = message;
        this.errorEl.hidden = false;
    }
}

function labelledInput(_label: string, type: string, value: string, placeholder: string): HTMLInputElement {
    const input = document.createElement('input');
    input.type = type;
    input.className = 'wte__input';
    input.value = value;
    input.placeholder = placeholder;
    return input;
}

function wrapField(labelText: string, input: HTMLElement): HTMLElement {
    const wrap = document.createElement('label');
    wrap.className = 'wte__field';
    const span = document.createElement('span');
    span.textContent = labelText;
    wrap.append(span, input);
    return wrap;
}

function numInput(label: string, value: number | undefined, onChange: (v: number | undefined) => void): HTMLElement {
    const wrap = document.createElement('label');
    wrap.className = 'wte__num';
    const span = document.createElement('span');
    span.textContent = label;
    const input = document.createElement('input');
    input.type = 'number';
    input.min = '0';
    input.step = 'any';
    input.className = 'wte__input';
    if (value != null) input.value = String(value);
    input.addEventListener('input', () => {
        const raw = input.value.trim();
        if (!raw) { onChange(undefined); return; }
        const n = Number(raw);
        onChange(Number.isFinite(n) && n >= 0 ? n : undefined);
    });
    wrap.append(span, input);
    return wrap;
}

function iconBtn(label: string, onClick: () => void): HTMLButtonElement {
    const btn = document.createElement('button');
    btn.type = 'button';
    btn.className = 'wte__btn wte__icon';
    btn.textContent = label;
    btn.addEventListener('click', onClick);
    return btn;
}

if (!customElements.get('workout-template-editor')) {
    customElements.define('workout-template-editor', WorkoutTemplateEditor);
}
